import React, { useState, useEffect } from 'react';
import axios from 'axios';

const AdminPanel = () => {
  // --- STATES ---
  const [activeTab, setActiveTab] = useState('create'); // 'create' or 'manage'
  const [postType, setPostType] = useState('blog'); 
  const [category, setCategory] = useState('electronics');
  const [formData, setFormData] = useState({ title: '', description: '', loc: '', salary: '', type: 'On-site' });
  const [file, setFile] = useState(null);
  const [items, setItems] = useState([]); // Database items for manage view

  // --- FETCH DATA (MANAGE TAB KE LIYE) ---
  const fetchItems = async () => {
    try {
      const url = postType === 'job' 
        ? 'http://localhost:5001/api/jobs' 
        : `http://localhost:5001/api/blog/${category}`;
      const res = await axios.get(url);
      setItems(res.data);
    } catch (err) {
      console.error("Fetch Error:", err);
    }
  };

  useEffect(() => {
    if (activeTab === 'manage') fetchItems();
  }, [activeTab, postType, category]);

  // --- DELETE LOGIC ---
  const handleDelete = async (id) => {
    if (window.confirm("Kyan aap ise delete karna chahte hain?")) {
      try {
        const endpoint = postType === 'job' ? 'jobs' : 'blog';
        await axios.delete(`http://localhost:5001/api/admin/${endpoint}/${id}`);
        alert("Deleted Successfully!");
        fetchItems(); 
      } catch (err) {
        alert("Delete fail ho gaya");
      }
    }
  };

  // --- SUBMIT LOGIC ---
  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      let response;
      if (postType === 'job') {
        response = await axios.post('http://localhost:5001/api/admin/jobs', formData);
      } else {
        const data = new FormData();
        data.append('category', category);
        data.append('title', formData.title);
        data.append('description', formData.description);
        if (file) data.append('image', file);
        response = await axios.post('http://localhost:5001/api/admin/blog', data);
      }

      if (response.status === 201 || response.status === 200) {
        alert("Published Successfully!");
        setFormData({ title: '', description: '', loc: '', salary: '', type: 'On-site' });
        setFile(null);
        e.target.reset();
      }
    } catch (err) {
      alert("Error: " + err.message);
    }
  };

  return (
    <div className="flex min-h-screen bg-gray-50 pt-10">

      {/* SIDEBAR */}
      <div className="w-80 bg-black text-white p-8 space-y-8 fixed h-full">
        <h2 className="text-2xl font-black text-orange-500 tracking-tighter">HUDSON ADMIN</h2>

        {/* NEW SWITCHES (TAB SYSTEM) */}
        <div className="space-y-2">
          <p className="text-[10px] font-black text-gray-500 uppercase tracking-widest mb-4">Operations</p>
          <button 
            onClick={() => setActiveTab('create')} 
            className={`w-full text-left p-4 rounded-2xl font-bold transition-all ${activeTab === 'create' ? 'bg-orange-600' : 'hover:bg-white/10 text-gray-400'}`}
          >
            ➕ Create New Post
          </button>
          <button 
            onClick={() => setActiveTab('manage')} 
            className={`w-full text-left p-4 rounded-2xl font-bold transition-all ${activeTab === 'manage' ? 'bg-orange-600' : 'hover:bg-white/10 text-gray-400'}`}
          >
            ⚙️ Manage Content
          </button>
        </div>

        <hr className="border-gray-800" />

        <div>
          <p className="text-[10px] font-black text-gray-500 uppercase tracking-widest mb-4">Post Type</p>
          <button onClick={() => setPostType('job')} className={`w-full text-left p-4 rounded-xl mb-2 font-bold ${postType === 'job' ? 'border border-orange-500' : 'text-gray-400'}`}>Careers / Jobs</button>
          <button onClick={() => setPostType('blog')} className={`w-full text-left p-4 rounded-xl font-bold ${postType === 'blog' ? 'border border-orange-500' : 'text-gray-400'}`}>Service Blogs</button>
        </div>

        {postType === 'blog' && (
          <div className="pl-4 border-l border-gray-800">
            {['electronics', 'electrical', 'chemical', 'industries'].map(cat => (
              <button key={cat} onClick={() => setCategory(cat)} className={`w-full text-left py-2 capitalize text-sm font-bold ${category === cat ? 'text-orange-500' : 'text-gray-500'}`}>
                • {cat}
              </button>
            ))}
          </div>
        )}
      </div>

      {/* MAIN AREA */}
      <div className="flex-1 ml-80 p-16">

        {/* CREATE VIEW */}
        {activeTab === 'create' && (
          <div className="max-w-3xl bg-white rounded-[3rem] p-12 shadow-sm border border-gray-100">
            <h1 className="text-4xl font-black tracking-tighter mb-10">Add {postType === 'job' ? 'Job' : category.toUpperCase()}</h1>
            <form onSubmit={handleSubmit} className="space-y-6">
              <input required placeholder="Title" className="w-full p-5 bg-gray-50 rounded-2xl outline-none font-bold" 
                value={formData.title} onChange={e => setFormData({...formData, title: e.target.value})} />

              {postType === 'blog' ? (
                <>
                  <textarea rows="5" placeholder="Description" className="w-full p-5 bg-gray-50 rounded-2xl outline-none font-bold"
                    value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})}></textarea>
                  <input type="file" className="w-full p-4 border-2 border-dashed rounded-2xl" onChange={e => setFile(e.target.files[0])} />
                </>
              ) : (
                <div className="grid grid-cols-2 gap-6">
                  <input placeholder="Location" className="p-5 bg-gray-50 rounded-2xl outline-none" value={formData.loc} onChange={e => setFormData({...formData, loc: e.target.value})} />
                  <input placeholder="Salary" className="p-5 bg-gray-50 rounded-2xl outline-none" value={formData.salary} onChange={e => setFormData({...formData, salary: e.target.value})} />
                </div>
              )}
              <button type="submit" className="w-full bg-black text-white py-6 rounded-2xl font-black hover:bg-orange-600 transition-all shadow-xl">Publish</button>
            </form>
          </div>
        )}

        {/* MANAGE VIEW */}
        {activeTab === 'manage' && (
          <div className="max-w-4xl bg-white rounded-[3rem] p-12 shadow-sm border border-gray-100">
            <h1 className="text-4xl font-black mb-10">Manage {postType === 'job' ? 'Jobs' : category}</h1>
            <div className="space-y-4">
              {items.map((item) => (
                <div key={item._id} className="flex items-center justify-between p-6 bg-gray-50 rounded-2xl border border-gray-100 hover:border-orange-200 transition-all">
                  <div>
                    <h3 className="font-black text-xl">{item.title}</h3>
                    <p className="text-gray-400 text-xs uppercase font-bold">{item.loc || item.category}</p>
                  </div>
                  <button 
                    onClick={() => handleDelete(item._id)}
                    className="bg-red-50 text-red-500 px-6 py-2 rounded-xl font-black hover:bg-red-500 hover:text-white transition-all"
                  >
                    Delete
                  </button>
                </div>
              ))}
              {items.length === 0 && <p className="text-gray-400 italic">Is category mein koi data nahi hai.</p>}
            </div>
          </div>
        )}

      </div>
    </div>
  );
};

export default AdminPanel;
